security = HTTPBearer(auto_error=True)


def _hash_token(token: str) -> str:
    """Hash the token before using it as a Redis key to avoid storing raw tokens as keys."""
    return hashlib.sha256(token.encode("utf-8")).hexdigest()


async def _check_rate_limit(redis_client: redis.Redis, user_id: str) -> None:
    """Simple sliding window rate limiter per user."""
    rate_limit_key = f"rate_limit:{user_id}"
    current_time = int(time.time())
    window_start = current_time - RATE_LIMIT_WINDOW_SECONDS

    pipe = redis_client.pipeline()
    pipe.zremrangebyscore(rate_limit_key, 0, window_start)
    pipe.zcard(rate_limit_key)
    pipe.zadd(rate_limit_key, {str(current_time) + ":" + secrets.token_hex(4): current_time})
    pipe.expire(rate_limit_key, RATE_LIMIT_WINDOW_SECONDS)
    results = await pipe.execute()

    request_count = results[1]
    if request_count >= RATE_LIMIT_MAX_REQUESTS:
        raise HTTPException(
            status_code=status.HTTP_429_TOO_MANY_REQUESTS,
            detail="Rate limit exceeded",
            headers={"Retry-After": str(RATE_LIMIT_WINDOW_SECONDS)},
        )


async def validate_token(
    credentials: HTTPAuthorizationCredentials = Depends(security),
    redis_client: redis.Redis = Depends(get_redis),
) -> TokenData:
    """
    Dependency that validates OAuth 2.0 bearer tokens.
    Extracts the token from the Authorization header, hashes it,
    and checks if it exists in Redis cache.
    """
    token = credentials.credentials

    # Basic token format validation
    if not token or len(token) < 32 or len(token) > 512:
        logger.warning("Invalid token format received")
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Invalid token format",
            headers={"WWW-Authenticate": "Bearer error=\"invalid_token\""},
        )

    token_hash = _hash_token(token)
    redis_key = f"{REDIS_TOKEN_PREFIX}{token_hash}"

    try:
        token_data_raw = await redis_client.hgetall(redis_key)
    except redis.RedisError as e:
        logger.error(f"Redis error during token validation: {e}")
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail="Authentication service temporarily unavailable",
        )

    if not token_data_raw:
        logger.warning("Token not found in cache")
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Invalid or expired token",
            headers={"WWW-Authenticate": "Bearer error=\"invalid_token\""},
        )

    try:
        token_data = TokenData(
            user_id=token_data_raw["user_id"],
            scopes=token_data_raw["scopes"].split(",") if token_data_raw.get("scopes") else [],
            issued_at=float(token_data_raw["issued_at"]),
            expires_at=float(token_data_raw["expires_at"]),
        )
    except (KeyError, ValueError) as e:
        logger.error(f"Corrupted token data in cache: {e}")
        # Remove corrupted entry
        await redis_client.delete(redis_key)
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Invalid token data",
            headers={"WWW-Authenticate": "Bearer error=\"invalid_token\""},
        )

    # Check expiration (defense in depth - Redis TTL should handle this too)
    current_time = time.time()
    if current_time >= token_data.expires_at:
        logger.info(f"Expired token used for user {token_data.user_id}")
        await redis_client.delete(redis_key)
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Token has expired",
            headers={"WWW-Authenticate": "Bearer error=\"invalid_token\""},
        )

    # Rate limiting per user
    await _check_rate_limit(redis_client, token_data.user_id)

    return token_data


def require_scopes(*required_scopes: str):
    """Factory for scope-checking dependencies."""

    async def _check_scopes(token_data: TokenData = Depends(validate_token)) -> TokenData:
        for scope in required_scopes:
            if scope not in token_data.scopes:
                logger.warning(
                    f"User {token_data.user_id} lacks required scope: {scope}"
                )
                raise HTTPException(
                    status_code=status.HTTP_403_FORBIDDEN,
                    detail=f"Insufficient scope. Required: {', '.join(required_scopes)}",
                    headers={
                        "WWW-Authenticate": f'Bearer error="insufficient_scope" scope="{" ".join(required_scopes)}"'
                    },
                )
        return token_data

    return _check_scopes


