@app.on_event("startup")
async def bootstrap_admin_token():
    """
    For development only: create an initial admin token if BOOTSTRAP_ADMIN_TOKEN env var is set.
    In production, tokens should be provisioned through a secure process.
    """
    bootstrap_token = os.environ.get("BOOTSTRAP_ADMIN_TOKEN")
    if not bootstrap_token or redis_pool is None:
        return

    if len(bootstrap_token) < 32:
        logger.warning("BOOTSTRAP_ADMIN_TOKEN is too short (min 32 chars). Skipping bootstrap.")
        return

    token_hash = _hash_token(bootstrap_token)
    redis_key = f"{REDIS_TOKEN_PREFIX}{token_hash}"

    current_time = time.time()
    expires_at = current_time + TOKEN_TTL_SECONDS

    token_record = {
        "user_id": "admin",
        "scopes": "read,write,admin",
        "issued_at": str(current_time),
        "expires_at": str(expires_at),
    }

    try:
        exists = await redis_pool.exists(redis_key)
        if not exists:
            pipe = redis_pool.pipeline()
            pipe.hset(redis_key, mapping=token_record)
            pipe.expire(redis_key, TOKEN_TTL_SECONDS)
            await pipe.execute()
            logger.info("Bootstrap admin token created")
        else:
            logger.info("Bootstrap admin token already exists")
    except redis.RedisError as e:
        logger.error(f"Failed to create bootstrap token: {e}")


